problems.answer:
An iterative C++ implementation is:

    long long fib(int n) {
        if (n < 0) throw std::invalid_argument("negative n");
        if (n <= 1) return n;
        long long prev = 0;
        long long curr = 1;
        for (int i = 2; i <= n; ++i) {
            long long next = prev + curr;
            prev = curr;
            curr = next;
        }
        return curr;
    }

