problems.answer:
Use Kadane's algorithm while tracking the best interval:

    #include <vector>
    #include <cstddef>

    template <typename T>
    std::vector<T> max_subarray(const std::vector<T>& a) {
        if (a.empty()) return {};

        T best = a[0];
        T current = a[0];
        std::size_t best_left = 0;
        std::size_t best_right = 0;
        std::size_t current_left = 0;

        for (std::size_t i = 1; i < a.size(); ++i) {
            if (current + a[i] < a[i]) {
                current = a[i];
                current_left = i;
            } else {
                current += a[i];
            }

            if (current > best) {
                best = current;
                best_left = current_left;
                best_right = i;
            }
        }

        return std::vector<T>(a.begin() + best_left, a.begin() + best_right + 1);
    }

