problems.answer:
A simple trial-division implementation is:

    #include <vector>

    std::vector<int> prime_factors(int n) {
        std::vector<int> factors;
        if (n <= 1) return factors;

        for (int d = 2; d <= n / d; ++d) {
            while (n % d == 0) {
                factors.push_back(d);
                n /= d;
            }
        }

        if (n > 1) factors.push_back(n);
        return factors;
    }

