problems.answer:
Only flip the two positions when their bits differ:

    #include <cstdint>

    std::uint64_t swap_bits(std::uint64_t x, unsigned i, unsigned j) {
        if (i == j) return x;

        std::uint64_t bit_i = (x >> i) & 1ULL;
        std::uint64_t bit_j = (x >> j) & 1ULL;

        if (bit_i != bit_j) {
            x ^= (1ULL << i) | (1ULL << j);
        }
        return x;
    }

