problems.answer:
A complete iterative reversal is:

    template <typename T>
    struct Node {
        T data;
        Node* next = nullptr;
    };

    template <typename T>
    Node<T>* reverse_list(Node<T>* head) {
        Node<T>* previous = nullptr;
        Node<T>* current = head;

        while (current != nullptr) {
            Node<T>* next = current->next;
            current->next = previous;
            previous = current;
            current = next;
        }
        return previous;
    }

